select
c.id, c.title, c.content, c.cover_img, c.media_urls, c.category_id, c.activity_sub_category_id, c.user_id, c.status, c.is_private, c.audit_reason,
c.is_top, c.view_count, c.like_count, c.favorite_count, c.comment_count,
c.price, c.trade_type, c.trade_condition, c.trade_status,
c.create_time, c.update_time,
cg.name as categoryName,
ascg.name as activitySubCategoryName
from content c
left join category cg on cg.id = c.category_id
left join activity_sub_category ascg on ascg.id = c.activity_sub_category_id


        and c.title like concat('%', #{title}, '%')


        and c.category_id = #{categoryId}


        and c.activity_sub_category_id = #{activitySubCategoryId}


        and c.status = #{status}


        and c.user_id = #{userId}


        and c.trade_type = #{tradeType}


        and c.trade_status = #{tradeStatus}


        and c.price >= #{minPrice}


        and c.price <= #{maxPrice}


        and ifnull(c.is_private, 0) = 0




        order by c.is_top desc, c.view_count desc, c.create_time desc


        order by c.is_top desc, c.like_count desc, c.create_time desc


        order by c.is_top desc, c.favorite_count desc, c.create_time desc


        order by c.is_top desc, c.create_time desc

select count(1)
from content


        and title like concat('%', #{title}, '%')


        and category_id = #{categoryId}


        and activity_sub_category_id = #{activitySubCategoryId}


        and status = #{status}


        and user_id = #{userId}


